    private List<Plant>? plants;
    private Plant newPlant = new();

    protected override async Task OnInitializedAsync()
    {
        await DbContext.Database.EnsureCreatedAsync();
        await LoadPlants();
    }

    private async Task LoadPlants()
    {
        var rawList = await DbContext.Plants.ToListAsync();
        plants = rawList.OrderBy(p => p.NextWateringDate).ToList();
    }

    private async Task WaterPlant(Plant plant)
    {
        plant.LastWateredDate = DateTime.Now;
        DbContext.Plants.Update(plant);
        await DbContext.SaveChangesAsync();
        await LoadPlants();
        Snackbar.Add($"Recorded watering for {plant.Name}!", Severity.Success);
    }

    private async Task SavePlant()
    {
        newPlant.LastWateredDate = DateTime.Now;
        DbContext.Plants.Add(newPlant);
        await DbContext.SaveChangesAsync();
        
        newPlant = new Plant(); 
        await LoadPlants();
        Snackbar.Add("New plant added!", Severity.Success);
    }

    private async Task DeletePlant(Plant plant)
    {
        DbContext.Plants.Remove(plant);
        await DbContext.SaveChangesAsync();
        await LoadPlants();
        Snackbar.Add($"Deleted {plant.Name}.", Severity.Warning);
    }

